"use strict";(self.webpackChunkdiscord_bots=self.webpackChunkdiscord_bots||[]).push([[688],{7585:(t,d,e)=>{e.r(d),e.d(d,{data:()=>o});const o={key:"v-2585c168",path:"/stiadsbot/commands.html",title:"Commands",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"How to Read",slug:"how-to-read",children:[{level:3,title:"Command",slug:"command",children:[]},{level:3,title:"Aliases",slug:"aliases",children:[]},{level:3,title:"Type",slug:"type",children:[]},{level:3,title:"Usage",slug:"usage",children:[]},{level:3,title:"Description",slug:"description",children:[]},{level:3,title:"Required Permissions",slug:"required-permissions",children:[]},{level:3,title:"Example & Result",slug:"example-result",children:[]}]},{level:2,title:"List of Commands",slug:"list-of-commands",children:[]}],filePathRelative:"stiadsbot/commands.md",git:{updatedTime:1629055125e3,contributors:[]}}},1781:(t,d,e)=>{e.r(d),e.d(d,{default:()=>a});const o=(0,e(6252).uE)('<h1 id="commands" tabindex="-1"><a class="header-anchor" href="#commands" aria-hidden="true">#</a> Commands</h1><h2 id="how-to-read" tabindex="-1"><a class="header-anchor" href="#how-to-read" aria-hidden="true">#</a> How to Read</h2><h3 id="command" tabindex="-1"><a class="header-anchor" href="#command" aria-hidden="true">#</a> Command</h3><p>This is the command name. This is what you enter to trigger the command.</p><h3 id="aliases" tabindex="-1"><a class="header-anchor" href="#aliases" aria-hidden="true">#</a> Aliases</h3><p>Aliases can also be entered in place of the command name, so that the same result can be obtained from multiple ways.</p><h3 id="type" tabindex="-1"><a class="header-anchor" href="#type" aria-hidden="true">#</a> Type</h3><p>The category, or group of commands that this command belongs in.</p><h3 id="usage" tabindex="-1"><a class="header-anchor" href="#usage" aria-hidden="true">#</a> Usage</h3><p>Usage defines how to use each item. Incorporate the prefix before. Items surrounded in angle brackets <code>&lt;&gt;</code> must be filled in which something. Items surrounded by square brackets <code>[]</code> are optional, the command will function without it. Items without any of those are inputted as-is. Items separated by a vertical line <code>|</code> mean either A <em>or</em> B, choose one. <code>()</code> is used to group together certain items.</p><h3 id="description" tabindex="-1"><a class="header-anchor" href="#description" aria-hidden="true">#</a> Description</h3><p>This is a description about what the command does.</p><h3 id="required-permissions" tabindex="-1"><a class="header-anchor" href="#required-permissions" aria-hidden="true">#</a> Required Permissions</h3><p>Some commands shouldn&#39;t be able to be executed by all members. These define the permissions the member must have in order to use the command.</p><h3 id="example-result" tabindex="-1"><a class="header-anchor" href="#example-result" aria-hidden="true">#</a> Example &amp; Result</h3><p>This is an example of the command used in action.</p><h2 id="list-of-commands" tabindex="-1"><a class="header-anchor" href="#list-of-commands" aria-hidden="true">#</a> List of Commands</h2><table><thead><tr><th>Command</th><th>Aliases</th><th>Type</th><th>Usage</th><th>Description</th><th>Required Permissions</th><th>Example &amp; Result</th></tr></thead><tbody><tr><td><code>8ball</code></td><td>N/A</td><td>Fun</td><td><code>8ball &lt;Query&gt;</code></td><td>Talk to the 8ball and ask a question.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>addxp</code></td><td>N/A</td><td>Leveling</td><td><code>addxp &lt;User ID&gt; &lt;Amount of Levels to Add&gt; &lt;Amount of XP to Add&gt;</code></td><td>Add xp to a user. Autoroles will afterwards need to be manually assigned.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>alwayswatching</code></td><td>N/A</td><td>Fun</td><td><code>alwayswatching</code></td><td>STIADS👀 Bot is always watching you, Mike Wazowski. Always watching. Always.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>announcements</code></td><td><code>messages</code></td><td>Info</td><td><code>announcements</code></td><td>If there are any announcements about STIADS👀 Bot or from cda94581, if anyone had the interest to check.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>avatar</code></td><td><code>av</code>, <code>icon</code>, <code>pfp</code></td><td>Info</td><td><code>avatar [@Mention Users]</code></td><td>Get a user&#39;s avatar.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>bite</code></td><td>N/A</td><td>Action</td><td><code>bite &lt;@Mention Users&gt;</code></td><td>Bite a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>blacklistxp</code></td><td><code>blxp</code></td><td>Leveling</td><td><code>blacklistxp (user|channel &lt;User ID&gt;)|list</code></td><td>Prevents a user or channel from gaining XP. There is currently an issue, where <code>list</code> doesn&#39;t work unless you add a random argument after that.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>blush</code></td><td>N/A</td><td>Action</td><td><code>blush &lt;@Mention Users&gt;</code></td><td>Blush at a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>cat</code></td><td>N/A</td><td>Fun</td><td><code>cat</code></td><td>Get a random cat picture from a <code>.json</code> file. This does not access an internet database, so images are limited.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>cda</code></td><td>N/A</td><td>Fun</td><td><code>cda</code></td><td>Information about a Child Development Associate</td><td>N/A</td><td>WIP</td></tr><tr><td><code>data</code></td><td><code>dontasktoask</code>, <code>don&#39;tasktoask</code></td><td>Other</td><td><code>data</code></td><td>A link to an explanation about how you shouldn&#39;t ask to ask for help.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>dog</code></td><td>N/A</td><td>Fun</td><td><code>dog</code></td><td>Get a random dog picture from a <code>.json</code> file. This does not access an internet database, so images are limited.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>help</code></td><td><code>commands</code></td><td>Other</td><td><code>help [Command Name]</code></td><td>Gets a list of all commands to use, or a description of a command if an argument is provided.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>hug</code></td><td>N/A</td><td>Action</td><td><code>hug &lt;@Mention Users&gt;</code></td><td>Hug a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>intro</code></td><td><code>hi</code>, <code>start</code></td><td>Info</td><td><code>intro</code></td><td>Get an introduction and information about STIADS👀 Bot.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>kiss</code></td><td>N/A</td><td>Action</td><td><code>kiss &lt;@Mention Users&gt;</code></td><td>Kiss a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>leaderboard</code></td><td>N/A</td><td>Leveling</td><td><code>leaderboard [Leaderboard Page]</code></td><td>Gets a server rank leaderboard, with 20 names displayed. An optional argument will switch to a different page.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>modifications</code></td><td>N/A</td><td>Fun</td><td><code>modifications [open|close]</code></td><td>Get information about modifications, or if an argument is specified, open or close modifications for submissions (requires Administrator).</td><td>N/A</td><td>WIP</td></tr><tr><td><code>modmessage</code></td><td>N/A</td><td>Moderation</td><td><code>modmessage &lt;User ID&gt; &lt;Message&gt;</code></td><td>DM a user a private message, for moderator/member contact.</td><td>Ban Members, Kick Members</td><td>WIP</td></tr><tr><td><code>moon</code></td><td>N/A</td><td>Fun</td><td><code>moon</code></td><td>Get information about a mysterious moon.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>movie</code></td><td>N/A</td><td>Info</td><td><code>movie</code></td><td>Information about an apparent cda94581 movie.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>nuzzle</code></td><td>N/A</td><td>Action</td><td><code>nuzzle &lt;@Mention Users&gt;</code></td><td>Nuzzle a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>ping</code></td><td>N/A</td><td>Info</td><td><code>ping</code></td><td>Checks the response time for STIADS👀 Bot, and if it&#39;s still alive.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>plans</code></td><td><code>future</code></td><td>Info</td><td><code>plans</code></td><td>Get the plans for the future of STIADS👀 Bot.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>poke</code></td><td>N/A</td><td>Action</td><td><code>poke &lt;@Mention Users&gt;</code></td><td>Poke a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>poll</code></td><td>N/A</td><td>Other</td><td><code>poll &lt;Poll Name&gt;,&lt;Options&gt;</code></td><td>Starts a poll on a certain topic. Up to 10 options can be created. Seperate the options with commas.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>pout</code></td><td>N/A</td><td>Action</td><td><code>pout &lt;@Mention Users&gt;</code></td><td>Pout at a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>purge</code></td><td><code>prune</code></td><td>Moderation</td><td><code>purge &lt;Amount&gt;</code></td><td>Purge messages in a channel. Max of 100.</td><td>Manage Messages</td><td>WIP</td></tr><tr><td><code>rank</code></td><td>N/A</td><td>Leveling</td><td><code>rank [User ID]</code></td><td>Gets the rank of the member, or the member if an argument is provided.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>removexp</code></td><td>N/A</td><td>Leveling</td><td><code>removexp &lt;User ID&gt; &lt;Amount of Levels to Remove&gt; &lt;Amount of XP to Remove&gt;</code></td><td>Removes XP from a user. Autoroles will need to be manually removed.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>resetxp</code></td><td>N/A</td><td>Leveling</td><td><code>resetxp &lt;User ID&gt;</code></td><td>Reset the XP of a user.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>revive</code></td><td><code>revive-chat</code></td><td>Fun</td><td><code>revive</code></td><td>Revives the chat...maybe?</td><td>N/A</td><td>WIP</td></tr><tr><td><code>rule</code></td><td>N/A</td><td>Info</td><td><code>rule &lt;Rule Number&gt;</code></td><td>Gets a rule from STIADS.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>server</code></td><td><code>serverinfo</code>, <code>server-info</code></td><td>Info</td><td><code>server</code></td><td>Get information about the server.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>setxp</code></td><td>N/A</td><td>Leveling</td><td><code>setxp &lt;User ID&gt; &lt;Level&gt; &lt;XP&gt;</code></td><td>Set the xp of a specific user. Autoroles will need to be manually assigned or removed. Take note of integer limits, if it fails to work.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>slap</code></td><td>N/A</td><td>Action</td><td><code>slap &lt;@Mention Users&gt;</code></td><td>Slap a user.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>stare</code></td><td>N/A</td><td>Action</td><td><code>stare &lt;@Mention Users&gt;</code></td><td>Stare at a user.</td><td>N/A</td><td>WIP</td></tr></tbody></table>',18),a={render:function(t,d){return o}}}}]);